'use client'
import { useState } from "react";
import Link from "next/link";
import Image from "next/image";
import logo from "@/public/logo.png";


const Login = () => {
  const [formData, setFormData] = useState({
    identifier: "", // Email or Username
    password: "",
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log("Logging in with:", formData);
    // Handle authentication logic here
  };

  return (
    <div className="flex flex-col min-h-screen items-center justify-center bg-white text-black">
        <div>
            <Image src={logo} alt="Logo" width={400} height={100} />
        </div>
        <h2 className="mb-6 text-center text-2xl font-semibold font-[jua] text-gray-700">Create your account</h2>
      <div className="w-full max-w-md border-[1px] rounded-[8px] border-[#D9D9D9] bg-white p-8">
        <form onSubmit={handleSubmit}>
          <div className="mb-4">
            <label className="mb-2 block text-sm font-medium text-gray-600">Email or Username</label>
            <input
              type="text"
              name="identifier"
              value={formData.identifier}
              onChange={handleChange}
              className="w-full p-2 focus:border-blue-500 focus:outline-none border-[1px] rounded-[8px] border-[#D9D9D9]"
              required
            />
          </div>
          <div className="mb-4">
            <label className="mb-2 block text-sm font-medium text-gray-600">Password</label>
            <input
              type="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              className="w-full p-2 focus:border-blue-500 focus:outline-none border-[1px] rounded-[8px] border-[#D9D9D9]"
              required
            />
          </div>
          
          <button
            type="submit"
            className="w-full rounded-md bg-gradient-to-r from-[#0090FF] to-[#00FF94] hover:from-[#00FF94] hover:to-[#0090FF] transition-all px-4 py-2 text-white"
          >
            Sign up
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;
